import boto3
import os
from botocore.exceptions import ClientError

def list_s3_files():
    """
    Lists all files in the specified S3 bucket.
    Credentials must be provided via environment variables or AWS credentials file.
    """
    
    # Load credentials from environment variables
    aws_access_key = os.environ.get('AWS_ACCESS_KEY_ID')
    aws_secret_key = os.environ.get('AWS_SECRET_ACCESS_KEY')
    bucket_name = os.environ.get('S3_BUCKET_NAME', 'demo-bucket')
    
    # Validate that credentials are provided
    if not aws_access_key or not aws_secret_key:
        print("ERROR: AWS credentials not found!")
        print("\nPlease set the following environment variables before running:")
        print("  export AWS_ACCESS_KEY_ID='your-access-key'")
        print("  export AWS_SECRET_ACCESS_KEY='your-secret-key'")
        print("  export S3_BUCKET_NAME='demo-bucket'  # Optional, defaults to 'demo-bucket'")
        print("\nAlternatively, configure AWS CLI with 'aws configure'")
        return
    
    try:
        # Create S3 client with credentials from environment
        s3_client = boto3.client(
            's3',
            aws_access_key_id=aws_access_key,
            aws_secret_access_key=aws_secret_key
        )
        
        print(f"Connecting to S3 bucket: {bucket_name}")
        print("-" * 50)
        
        # List objects in the bucket
        response = s3_client.list_objects_v2(Bucket=bucket_name)
        
        if 'Contents' in response:
            print(f"Found {len(response['Contents'])} files:\n")
            for obj in response['Contents']:
                print(f"  - {obj['Key']} (Size: {obj['Size']} bytes, Last Modified: {obj['LastModified']})")
        else:
            print("No files found in the bucket.")
            
    except ClientError as e:
        error_code = e.response['Error']['Code']
        if error_code == 'NoSuchBucket':
            print(f"ERROR: Bucket '{bucket_name}' does not exist.")
        elif error_code == 'InvalidAccessKeyId':
            print("ERROR: Invalid AWS Access Key ID.")
        elif error_code == 'SignatureDoesNotMatch':
            print("ERROR: Invalid AWS Secret Access Key.")
        elif error_code == 'AccessDenied':
            print("ERROR: Access denied. Check your IAM permissions.")
        else:
            print(f"ERROR: {e}")
    except Exception as e:
        print(f"Unexpected error: {e}")

if __name__ == "__main__":
    list_s3_files()